"modify.frame" <-
function (dfr, ...) 
{
        nm <- names(dfr)
        e <- substitute(list(...))
        if (length(e) < 2) 
                return(dfr)
        subst.call <- function(e) {
                if (length(e) > 1) 
                        for (i in 2:length(e)) e[[i]] <- subst.expr(e[[i]])
                substitute(e)
        }
        subst.expr <- function(e) {
                if (is.call(e)) 
                        subst.call(e)
                else match.expr(e)
        }
        match.expr <- function(e) {
                if (is.na(n <- match(as.character(e), nm))) 
                        if (is.atomic(e)) 
                                e
                        else substitute(e)
                else substitute(dfr[, n])
        }
        tags <- names(as.list(e))
        for (i in 2:length(e)) {
                ee <- subst.expr(e[[i]])
                r <- eval(ee)
                if (!is.na(tags[i])) {
                        if (is.na(n <- match(as.character(tags[i]), 
                                nm))) {
                                n <- length(nm) + 1
                                dfr[[n]] <- numeric(nrow(dfr))
                                names(dfr)[n] <- tags[i]
                                nm <- names(dfr)
                        }
                        dfr[[tags[i]]][] <- r
                }
        }
        dfr
}
"subset.frame" <-
function (dfr, expr) 
{
        nm <- names(dfr)
        e <- substitute(expr)
        subst.call <- function(e) {
                if (length(e) > 1) 
                        for (i in 2:length(e)) e[[i]] <- subst.expr(e[[i]])
